import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { getDocuments, updateDocument } from "../../features/Document/DocumentSlice";
import { toast } from "react-toastify";
import 'react-toastify/dist/ReactToastify.css';
import ImageModal from "../../components/ImageModel";
import { 
  FileCheck, 
  ShieldCheck, 
  XCircle, 
  FileText, 
  Eye, 
  Clock, 
  CheckCircle2, 
  AlertCircle,
  Hash,
  Activity,
  UserCheck
} from "lucide-react";

const DocumentsList = () => {
  const dispatch = useDispatch();
  const { documents, isLoading, isError } = useSelector((state) => state.document);
  
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedImage, setSelectedImage] = useState("");

  useEffect(() => {
    dispatch(getDocuments());
  }, [dispatch]);

  const handleAccept = (id) => {
    dispatch(updateDocument({ id, status: "approved" }))
      .unwrap()
      .then(() => {
        toast.success(`Protocol Authorization Successful: Entity ${id.slice(-6)} verified.`);
        dispatch(getDocuments());
      })
      .catch((err) => toast.error(`Authorization Failed: ${err.message}`));
  };

  const handleReject = (id) => {
    dispatch(updateDocument({ id, status: "rejected" }))
      .unwrap()
      .then(() => {
        toast.warning(`Protocol Rejection: Entity ${id.slice(-6)} flagged for review.`);
        dispatch(getDocuments());
      })
      .catch((err) => toast.error(`Operation Failed: ${err.message}`)); 
  };

  const openModal = (imageUrl) => {
    setSelectedImage(imageUrl);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedImage("");
  };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
        <div className="w-12 h-12 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin" />
        <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Synchronizing Archives...</span>
      </div>
    );
  }

  if (isError) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[40vh] bg-rose-50/50 rounded-[32px] border border-rose-100 p-12">
        <AlertCircle size={48} className="text-rose-500 mb-4" />
        <h3 className="text-[18px] font-black text-slate-900 uppercase tracking-tighter">Cipher Stream Error</h3>
        <p className="text-slate-500 font-bold mt-1 uppercase tracking-widest text-xs">No merchant documents found in active registry.</p>
      </div>
    );
  }

  const newDocuments = documents?.data;

  return (
    <div className="space-y-12 pb-20 animate-in fade-in slide-in-from-bottom-6 duration-700">
      {/* Station Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 px-2">
        <div className="space-y-2">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-1.5 h-1.5 rounded-full bg-indigo-600 animate-pulse" />
            <span className="text-[11px] font-black text-indigo-600 uppercase tracking-[0.3em]">Credentials Hub</span>
          </div>
          <h1 className="text-[42px] font-black text-slate-900 tracking-tighter leading-none">
            Compliance <span className="text-indigo-600">Archive</span>
          </h1>
          <p className="text-[16px] text-slate-400 font-bold max-w-xl">
            Surveillance of merchant identities, tax registration certifications, and operational licenses.
          </p>
        </div>
        
        <div className="flex items-center gap-2 bg-indigo-50 px-6 py-3 rounded-[22px] border border-indigo-100">
          <UserCheck size={20} className="text-indigo-600" />
          <span className="text-[13px] font-black text-indigo-700 uppercase tracking-widest italic">
            {newDocuments?.length || 0} Entities Awaiting Verification
          </span>
        </div>
      </div>

      {newDocuments && newDocuments.length > 0 ? (
        <div className="grid gap-8 lg:grid-cols-2 xl:grid-cols-3">
          {newDocuments.map((doc) => (
            <div
              key={doc._id}
              className="group enterprise-card bg-white flex flex-col relative overflow-hidden transition-all duration-500 hover:shadow-2xl hover:shadow-indigo-500/10 border-indigo-100/50"
            >
              {/* Background Accent */}
              <div className="absolute top-0 right-0 p-8 opacity-[0.03] group-hover:scale-110 group-hover:opacity-[0.05] transition-all duration-700 pointer-events-none">
                  <ShieldCheck size={180} />
              </div>

              {/* Card Header */}
              <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
                  <div className="flex items-center gap-4">
                      <div className="w-12 h-12 rounded-[18px] bg-slate-900 text-white flex items-center justify-center shadow-lg group-hover:bg-indigo-600 transition-all duration-500">
                          <FileText size={22} />
                      </div>
                      <div>
                          <div className="flex items-center gap-2 mb-0.5">
                             <Hash size={12} className="text-slate-300" />
                             <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">TIN REGISTRY</span>
                          </div>
                          <h3 className="text-[18px] font-black text-slate-900 leading-none uppercase tracking-tighter">{doc.TinNumber}</h3>
                      </div>
                  </div>
                  <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border border-current ${
                      doc.status === 'approved' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 
                      doc.status === 'rejected' ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-amber-50 text-amber-600 border-amber-100'
                  }`}>
                      {doc.status}
                  </div>
              </div>

              {/* Image Matrix */}
              <div className="p-8 space-y-8 flex-1">
                {/* Product/License Images */}
                <div className="space-y-4">
                    <div className="flex items-center justify-between">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Authority Documents</label>
                        <span className="flex items-center gap-1.5 text-[10px] font-black text-indigo-600 italic">
                            <Eye size={12} /> Click to Inspect
                        </span>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      {doc.images && doc.images.length > 0 ? (
                        doc.images.map((img, index) => (
                          <div key={index} className="relative group/img overflow-hidden rounded-[20px] aspect-square bg-slate-50 border border-slate-100 cursor-pointer shadow-inner" onClick={() => openModal(img.secure_url)}>
                              <img
                                src={img.secure_url}
                                alt="document"
                                className="w-full h-full object-cover transition-all duration-700 group-hover/img:scale-110 group-hover/img:brightness-50"
                              />
                              <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover/img:opacity-100 transition-opacity">
                                  <Eye size={24} className="text-white drop-shadow-lg" />
                              </div>
                          </div>
                        ))
                      ) : (
                        <div className="col-span-2 p-8 rounded-[20px] bg-slate-50 border border-dashed border-slate-200 flex flex-col items-center justify-center text-center">
                            <AlertCircle size={24} className="text-slate-300 mb-2" />
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">No visual data indexed</p>
                        </div>
                      )}
                    </div>
                </div>

                {/* ID Card Images */}
                <div className="space-y-4">
                    <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Biometric ID Protocol</label>
                    <div className="grid grid-cols-2 gap-4">
                      {doc.idCardImages && doc.idCardImages.length > 0 ? (
                        doc.idCardImages.map((img, index) => (
                          <div key={index} className="relative group/img overflow-hidden rounded-[20px] aspect-[1.5/1] bg-slate-50 border border-slate-100 cursor-pointer shadow-inner" onClick={() => openModal(img.secure_url)}>
                              <img
                                src={img.secure_url}
                                alt="ID card"
                                className="w-full h-full object-cover transition-all duration-700 group-hover/img:scale-110 group-hover/img:brightness-50"
                              />
                               <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover/img:opacity-100 transition-opacity">
                                  <Eye size={24} className="text-white drop-shadow-lg" />
                              </div>
                          </div>
                        ))
                      ) : (
                         <div className="col-span-2 p-8 rounded-[20px] bg-slate-50 border border-dashed border-slate-200 flex flex-col items-center justify-center text-center">
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Awaiting ID Verification</p>
                        </div>
                      )}
                    </div>
                </div>
              </div>

              {/* Action Hub */}
              <div className="p-8 pt-0 flex gap-4 mt-auto">
                <button
                  onClick={() => handleAccept(doc._id)}
                  className="flex-1 h-14 bg-emerald-600 hover:bg-emerald-700 text-white font-black uppercase text-[11px] tracking-[0.2em] rounded-2xl shadow-xl shadow-emerald-500/20 transition-all active:scale-95 flex items-center justify-center gap-2"
                >
                  <CheckCircle2 size={18} /> Authorize
                </button>
                <button
                  onClick={() => handleReject(doc._id)}
                  className="flex-1 h-14 bg-rose-50 hover:bg-rose-100 text-rose-600 font-black uppercase text-[11px] tracking-[0.2em] rounded-2xl border border-rose-200 transition-all active:scale-95 flex items-center justify-center gap-2"
                >
                  <XCircle size={18} /> Flag Protocol
                </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="max-w-2xl mx-auto py-32 text-center bg-white rounded-[48px] border border-slate-100 shadow-2xl">
           <div className="w-20 h-20 bg-slate-50 rounded-[30px] flex items-center justify-center mx-auto mb-8">
              <ShieldCheck size={40} className="text-slate-300" />
           </div>
           <h3 className="text-[24px] font-black text-slate-900 uppercase tracking-tighter">Zero Pending Clearances</h3>
           <p className="text-slate-400 font-bold mt-2 uppercase tracking-widest text-sm italic">All merchant archives are currently synchronized.</p>
        </div>
      )}

      {/* Image Modal */}
      <ImageModal isOpen={isModalOpen} imageUrl={selectedImage} onClose={closeModal} />
      
      <style>{`
        .enterprise-card {
           background: #ffffff;
           border-radius: 40px;
           border: 1.5px solid #f8fafc;
           box-shadow: 0 10px 30px rgba(0,0,0,0.02);
        }
      `}</style>
    </div>
  );
};

export default DocumentsList;
